-- Seed: On This Day — 210 presidential history facts across all 12 months
-- Format: "On this day in [year], [engaging narrative]"
-- Categories: birth, death, inauguration, legislation, war, scandal, achievement

INSERT INTO on_this_day (month, day, year, president_id, fact, category) VALUES

-- ─── JANUARY ──────────────────────────────────────────────────────────────────

(1, 1, 1863,  (SELECT id FROM presidents WHERE number = 16), 'On this day in 1863, President Abraham Lincoln signed the Emancipation Proclamation, declaring all enslaved people in Confederate states to be forever free — a pivotal executive act that transformed the Civil War into a crusade for human freedom.', 'legislation'),
(1, 5, 1933,  (SELECT id FROM presidents WHERE number = 30), 'On this day in 1933, Calvin Coolidge died quietly of a heart attack at his home in Northampton, Massachusetts, at age 60. Known as "Silent Cal," he presided over the booming 1920s economy and believed "the business of America is business."', 'death'),
(1, 6, 1941,  (SELECT id FROM presidents WHERE number = 32), 'On this day in 1941, President Franklin D. Roosevelt delivered his famous "Four Freedoms" speech to Congress, articulating freedom of speech, freedom of worship, freedom from want, and freedom from fear as the essential rights of all human beings.', 'achievement'),
(1, 7, 1800,  (SELECT id FROM presidents WHERE number = 13), 'On this day in 1800, Millard Fillmore was born in a log cabin in Summerhill, New York — the last Whig president, he signed the Compromise of 1850 and helped delay civil war for a decade, though critics say he only postponed the inevitable.', 'birth'),
(1, 8, 1815,  (SELECT id FROM presidents WHERE number = 7),  'On this day in 1815, future President Andrew Jackson secured a stunning American victory at the Battle of New Orleans, defeating a much larger British force and cementing his reputation as a military hero — launching him toward the White House.', 'war'),
(1, 9, 1913,  (SELECT id FROM presidents WHERE number = 37), 'On this day in 1913, Richard Nixon was born in Yorba Linda, California — the only U.S. president to resign from office. He opened diplomatic relations with China, created the EPA, and ended the Vietnam War draft, before Watergate consumed his presidency.', 'birth'),
(1, 14, 1784, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1784, the Continental Congress ratified the Treaty of Paris, officially ending the Revolutionary War. General George Washington, the future first president, had commanded the army to the victory that made this treaty possible.', 'achievement'),
(1, 16, 1991, (SELECT id FROM presidents WHERE number = 41), 'On this day in 1991, President George H.W. Bush launched Operation Desert Storm, beginning the air campaign to liberate Kuwait from Iraqi occupation. The war lasted just 100 hours of ground combat and was one of the most decisive military victories in American history.', 'war'),
(1, 17, 1893, (SELECT id FROM presidents WHERE number = 19), 'On this day in 1893, Rutherford B. Hayes died at age 70 at his home in Fremont, Ohio. The president who ended Reconstruction by withdrawing federal troops from the South, his legacy remains deeply contested among historians.', 'death'),
(1, 18, 1862, (SELECT id FROM presidents WHERE number = 10), 'On this day in 1862, John Tyler died at age 71 — the first vice president to assume the presidency upon a president''s death. He was the only former U.S. president to die as an official of the Confederate government, having won election to the Confederate House.', 'death'),
(1, 20, 1961, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1961, President John F. Kennedy delivered one of the most celebrated inaugural addresses in American history, challenging his fellow citizens: "Ask not what your country can do for you — ask what you can do for your country."', 'inauguration'),
(1, 20, 1981, (SELECT id FROM presidents WHERE number = 40), 'On this day in 1981, Ronald Reagan was inaugurated as the 40th president — and within minutes of his taking the oath, Iran released 52 American hostages who had been held captive for 444 days, a coincidence that his critics called a carefully engineered October Surprise.', 'inauguration'),
(1, 20, 2009, (SELECT id FROM presidents WHERE number = 44), 'On this day in 2009, Barack Obama was inaugurated as the 44th — and first African American — president of the United States, drawing nearly two million people to the National Mall in one of the most historic moments in American political life.', 'inauguration'),
(1, 22, 1973, (SELECT id FROM presidents WHERE number = 36), 'On this day in 1973, Lyndon B. Johnson died of a heart attack at his Texas ranch at age 64 — the very same day the Supreme Court handed down the Roe v. Wade decision, a ruling he never knew about.', 'death'),
(1, 29, 1843, (SELECT id FROM presidents WHERE number = 25), 'On this day in 1843, William McKinley was born in Niles, Ohio. The last president to have served in the Civil War, he led America to victory in the Spanish-American War before being assassinated in 1901, just six months into his second term.', 'birth'),
(1, 30, 1835, (SELECT id FROM presidents WHERE number = 7),  'On this day in 1835, Andrew Jackson survived the first assassination attempt on a sitting U.S. president when gunman Richard Lawrence''s two pistols both misfired at point-blank range in the Capitol Rotunda. Jackson, furious, attacked his assailant with his cane.', 'achievement'),
(1, 30, 1882, (SELECT id FROM presidents WHERE number = 32), 'On this day in 1882, Franklin Delano Roosevelt was born at Springwood estate in Hyde Park, New York. He would serve an unprecedented four terms as president, guiding America through the Great Depression and World War II — the defining crises of the 20th century.', 'birth'),
(1, 31, 1865, (SELECT id FROM presidents WHERE number = 16), 'On this day in 1865, the U.S. House of Representatives passed the 13th Amendment abolishing slavery. President Lincoln had personally lobbied reluctant congressmen, and he considered securing the votes his greatest achievement as president.', 'legislation'),

-- ─── FEBRUARY ─────────────────────────────────────────────────────────────────

(2, 3, 1870,  (SELECT id FROM presidents WHERE number = 18), 'On this day in 1870, the 15th Amendment to the Constitution was ratified, granting Black men the right to vote. President Ulysses S. Grant championed it and later signed the Enforcement Acts to protect these new voting rights against Klan violence in the South.', 'legislation'),
(2, 3, 1924,  (SELECT id FROM presidents WHERE number = 28), 'On this day in 1924, Woodrow Wilson died at his home in Washington, D.C., at age 67. The idealistic 28th president led America through World War I, won the Nobel Peace Prize, and championed the League of Nations — only to watch the Senate reject it.', 'death'),
(2, 4, 1789,  (SELECT id FROM presidents WHERE number = 1),  'On this day in 1789, the Electoral College unanimously elected George Washington as the first President of the United States — the only president ever to receive all electoral votes, a testament to the extraordinary trust the nation placed in him.', 'achievement'),
(2, 5, 1937,  (SELECT id FROM presidents WHERE number = 32), 'On this day in 1937, President Franklin D. Roosevelt unveiled his controversial "court-packing" plan, proposing to add up to six new justices to a Supreme Court that was blocking his New Deal. Even his allies called it an assault on judicial independence.', 'scandal'),
(2, 6, 1911,  (SELECT id FROM presidents WHERE number = 40), 'On this day in 1911, Ronald Reagan was born in Tampico, Illinois. A former actor who became governor of California, he transformed American conservatism as the 40th president, cut taxes, rebuilt the military, and helped end the Cold War.', 'birth'),
(2, 9, 1773,  (SELECT id FROM presidents WHERE number = 9),  'On this day in 1773, William Henry Harrison was born in Charles City County, Virginia. He would deliver the longest inaugural address in U.S. history — nearly two hours, in freezing rain without a hat or coat — then die of pneumonia 31 days later.', 'birth'),
(2, 12, 1809, (SELECT id FROM presidents WHERE number = 16), 'On this day in 1809, Abraham Lincoln was born in a one-room log cabin in Hardin County, Kentucky. The 16th president guided the nation through its bloodiest conflict, ended slavery, and preserved the Union — before being assassinated at Ford''s Theatre in 1865.', 'birth'),
(2, 17, 1801, (SELECT id FROM presidents WHERE number = 3),  'On this day in 1801, Thomas Jefferson was elected president by the U.S. House of Representatives after a tie in the Electoral College with Aaron Burr — the only presidential election in American history ever decided by the House of Representatives.', 'achievement'),
(2, 20, 1962, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1962, astronaut John Glenn became the first American to orbit Earth, completing three orbits in Friendship 7. President Kennedy''s aggressive space program had been vindicated, and Glenn became an instant national hero.', 'achievement'),
(2, 21, 1972, (SELECT id FROM presidents WHERE number = 37), 'On this day in 1972, President Richard Nixon arrived in Beijing for his historic visit to China — breaking 23 years of diplomatic isolation. Nixon called it "the week that changed the world," and the opening of China remains one of the most consequential acts of his presidency.', 'achievement'),
(2, 22, 1732, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1732, George Washington was born in Westmoreland County, Virginia. The Father of His Country would command the Continental Army, preside over the Constitutional Convention, serve as America''s first president, and voluntarily surrender power — setting a precedent that endured for 150 years.', 'birth'),
(2, 23, 1945, (SELECT id FROM presidents WHERE number = 33), 'On this day in 1945, Associated Press photographer Joe Rosenthal captured the iconic image of six Marines raising the American flag on Iwo Jima. President Truman called the battle "the greatest feat of arms any branch of our military had ever been called upon to perform."', 'war'),
(2, 24, 1868, (SELECT id FROM presidents WHERE number = 17), 'On this day in 1868, the U.S. House of Representatives voted to impeach President Andrew Johnson — the first impeachment of a U.S. president. He survived removal by a single vote in the Senate, a margin that haunted American politics for decades.', 'scandal'),
(2, 25, 1791, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1791, President George Washington signed the charter establishing the First Bank of the United States, despite fierce opposition from Thomas Jefferson and James Madison who believed it was unconstitutional — the first great debate over federal power.', 'legislation'),
(2, 26, 1993, (SELECT id FROM presidents WHERE number = 42), 'On this day in 1993, terrorists detonated a truck bomb in the parking garage beneath the World Trade Center, killing six people and injuring over 1,000. It was an early warning of the rising threat of international terrorism that President Clinton''s administration would struggle to contain.', 'war'),
(2, 28, 1844, (SELECT id FROM presidents WHERE number = 10), 'On this day in 1844, an explosion aboard the USS Princeton killed eight people, including two Cabinet secretaries, while President John Tyler and his guests were below deck. Tyler narrowly escaped death in the first major disaster to befall a sitting president.', 'achievement'),

-- ─── MARCH ────────────────────────────────────────────────────────────────────

(3, 4, 1861,  (SELECT id FROM presidents WHERE number = 16), 'On this day in 1861, Abraham Lincoln delivered his first inaugural address to a nation on the brink of civil war, pleading for unity: "We are not enemies, but friends. We must not be enemies. Though passion may have strained, it must not break our bonds of affection."', 'inauguration'),
(3, 4, 1865,  (SELECT id FROM presidents WHERE number = 16), 'On this day in 1865, President Lincoln delivered his second inaugural address — considered one of the greatest speeches in American history — calling for "malice toward none" and "charity for all" as the Civil War approached its end.', 'achievement'),
(3, 4, 1933,  (SELECT id FROM presidents WHERE number = 32), 'On this day in 1933, Franklin D. Roosevelt was inaugurated at the depth of the Great Depression, declaring "the only thing we have to fear is fear itself." He immediately launched a flurry of executive action in his famous first 100 days, reshaping American government.', 'inauguration'),
(3, 5, 1770,  (SELECT id FROM presidents WHERE number = 2),  'On this day in 1770, British soldiers fired on a crowd of colonists in what became known as the Boston Massacre, killing five. Future President John Adams controversially defended the soldiers in court — arguing that the rule of law must prevail even over popular passion.', 'war'),
(3, 8, 1930,  (SELECT id FROM presidents WHERE number = 27), 'On this day in 1930, William Howard Taft died at age 72 in Washington, D.C. He was the only man in American history to serve as both President of the United States and Chief Justice of the Supreme Court — a fact he reportedly found more fulfilling than the presidency.', 'death'),
(3, 12, 1947, (SELECT id FROM presidents WHERE number = 33), 'On this day in 1947, President Harry Truman addressed Congress to unveil the Truman Doctrine, pledging U.S. support for free peoples resisting communist subjugation. It became the cornerstone of American Cold War foreign policy for the next four decades.', 'achievement'),
(3, 15, 1767, (SELECT id FROM presidents WHERE number = 7),  'On this day in 1767, Andrew Jackson was born in the Waxhaw region of the Carolinas. The fiery frontiersman who survived duels, assassination attempts, and wars, he founded the modern Democratic Party and dramatically expanded the power of the presidency.', 'birth'),
(3, 16, 1751, (SELECT id FROM presidents WHERE number = 4),  'On this day in 1751, James Madison was born in Port Conway, Virginia. The "Father of the Constitution" co-authored the Federalist Papers, drafted the Bill of Rights, and served as 4th President — a presidency overshadowed by the burning of Washington in the War of 1812.', 'birth'),
(3, 18, 1837, (SELECT id FROM presidents WHERE number = 22), 'On this day in 1837, Grover Cleveland was born in Caldwell, New Jersey. The only president to serve two non-consecutive terms — the 22nd and 24th president — he is listed in the record books as two separate presidents despite being one man.', 'birth'),
(3, 23, 2010, (SELECT id FROM presidents WHERE number = 44), 'On this day in 2010, President Barack Obama signed the Affordable Care Act into law — the most sweeping healthcare reform in America since the creation of Medicare and Medicaid, extending health coverage to more than 20 million uninsured Americans.', 'legislation'),
(3, 25, 1965, (SELECT id FROM presidents WHERE number = 36), 'On this day in 1965, Martin Luther King Jr. led 25,000 civil rights marchers from Selma to Montgomery, Alabama. President Johnson leveraged the moral force of that march to push the Voting Rights Act through Congress just five months later.', 'achievement'),
(3, 28, 1969, (SELECT id FROM presidents WHERE number = 34), 'On this day in 1969, Dwight D. Eisenhower died at age 78 at Walter Reed Army Medical Center. The Supreme Commander who oversaw D-Day, he had warned in his farewell address of the dangers of the "military-industrial complex" — a phrase that still echoes today.', 'death'),
(3, 29, 1790, (SELECT id FROM presidents WHERE number = 10), 'On this day in 1790, John Tyler was born in Charles City County, Virginia. When President Harrison died after just 31 days, Tyler insisted on being president — not "acting president" — establishing the vital precedent of full vice-presidential succession.', 'birth'),
(3, 30, 1981, (SELECT id FROM presidents WHERE number = 40), 'On this day in 1981, President Ronald Reagan was shot outside the Washington Hilton Hotel by John Hinckley Jr. As he was wheeled into surgery, Reagan quipped to the doctors: "Please tell me you''re all Republicans." He recovered and resumed the presidency within weeks.', 'achievement'),
(3, 31, 1968, (SELECT id FROM presidents WHERE number = 36), 'On this day in 1968, President Lyndon B. Johnson shocked the nation by announcing he would not seek re-election, withdrawing from the 1968 presidential race amid the Vietnam War''s mounting casualties and a country deeply divided over his presidency.', 'achievement'),
(3, 13, 1901, (SELECT id FROM presidents WHERE number = 23), 'On this day in 1901, Benjamin Harrison, the 23rd president and grandson of the 9th, died of pneumonia at age 67 in Indianapolis. His single term saw six new states admitted to the Union and the first billion-dollar federal budget in American history.', 'death'),

-- ─── APRIL ────────────────────────────────────────────────────────────────────

(4, 3, 1948,  (SELECT id FROM presidents WHERE number = 33), 'On this day in 1948, President Harry Truman signed the Marshall Plan into law, authorizing $13 billion to rebuild war-ravaged Western Europe. It was the most successful foreign policy initiative in American history — reviving European democracies and countering Soviet expansion.', 'legislation'),
(4, 4, 1841,  (SELECT id FROM presidents WHERE number = 9),  'On this day in 1841, William Henry Harrison died of pneumonia just 31 days after his inauguration — the shortest presidency in American history. His death established the vital precedent that the vice president becomes fully president, not merely acting president.', 'death'),
(4, 6, 1917,  (SELECT id FROM presidents WHERE number = 28), 'On this day in 1917, the United States declared war on Germany, entering World War I. President Woodrow Wilson — who had run on "He kept us out of war" — told Congress that "the world must be made safe for democracy."', 'war'),
(4, 9, 1865,  (SELECT id FROM presidents WHERE number = 16), 'On this day in 1865, Confederate General Robert E. Lee surrendered to Ulysses S. Grant at Appomattox Court House, effectively ending the Civil War. President Lincoln heard the news in Washington just five days before he was assassinated.', 'war'),
(4, 12, 1861, (SELECT id FROM presidents WHERE number = 16), 'On this day in 1861, Confederate forces fired on Fort Sumter in South Carolina, beginning the American Civil War. President Lincoln''s call for 75,000 volunteers to suppress the rebellion prompted four more Southern states to secede.', 'war'),
(4, 12, 1945, (SELECT id FROM presidents WHERE number = 32), 'On this day in 1945, Franklin D. Roosevelt died suddenly of a cerebral hemorrhage at Warm Springs, Georgia, at age 63 — just 83 days into his unprecedented fourth term and three weeks before Germany''s surrender. Harry Truman was left to finish the war.', 'death'),
(4, 13, 1743, (SELECT id FROM presidents WHERE number = 3),  'On this day in 1743, Thomas Jefferson was born at Shadwell plantation in Virginia. The author of the Declaration of Independence, founder of the University of Virginia, and 3rd president, he doubled the size of America with the Louisiana Purchase for just $15 million.', 'birth'),
(4, 14, 1865, (SELECT id FROM presidents WHERE number = 16), 'On this day in 1865, Abraham Lincoln was shot by actor John Wilkes Booth at Ford''s Theatre in Washington, D.C., just five days after the Civil War effectively ended. He was the first U.S. president to be assassinated, dying the following morning.', 'death'),
(4, 17, 1961, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1961, the CIA-backed Bay of Pigs invasion of Cuba began — and immediately collapsed. The catastrophic failure humiliated President Kennedy, strengthened Fidel Castro''s hold on power, and led Kennedy to distrust the CIA for the rest of his presidency.', 'scandal'),
(4, 19, 1775, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1775, the first shots of the American Revolution were fired at Lexington and Concord in Massachusetts. The battles set future President George Washington on the path to becoming Commander of the Continental Army and, ultimately, the first president.', 'war'),
(4, 22, 1994, (SELECT id FROM presidents WHERE number = 37), 'On this day in 1994, former President Richard Nixon died in New York City at age 81, four days after suffering a massive stroke. Despite the Watergate scandal, he had spent his final two decades rebuilding his reputation as a global statesman and foreign policy sage.', 'death'),
(4, 23, 1791, (SELECT id FROM presidents WHERE number = 15), 'On this day in 1791, James Buchanan was born in Cove Gap, Pennsylvania. The only bachelor president, he served immediately before Lincoln and is consistently ranked among the worst presidents for his paralysis in the face of the secession crisis.', 'birth'),
(4, 25, 1898, (SELECT id FROM presidents WHERE number = 25), 'On this day in 1898, the United States officially declared war on Spain, launching the Spanish-American War. President McKinley''s decisive victory made America a Pacific power almost overnight, acquiring Puerto Rico, Guam, and the Philippines.', 'war'),
(4, 27, 1822, (SELECT id FROM presidents WHERE number = 18), 'On this day in 1822, Ulysses S. Grant was born in Point Pleasant, Ohio. The Union general who accepted Lee''s surrender at Appomattox, he served as the 18th president during Reconstruction — a period of tremendous achievement and tremendous corruption.', 'birth'),
(4, 28, 1758, (SELECT id FROM presidents WHERE number = 5),  'On this day in 1758, James Monroe was born in Westmoreland County, Virginia. The last Founding Father to serve as president, he presided over the "Era of Good Feelings" and proclaimed the Monroe Doctrine warning European powers to stay out of the Americas.', 'birth'),
(4, 30, 1789, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1789, George Washington was inaugurated as the first President of the United States on the balcony of Federal Hall in New York City, establishing every precedent and expectation for the office that every president since has been measured against.', 'inauguration'),

-- ─── MAY ──────────────────────────────────────────────────────────────────────

(5, 1, 1960,  (SELECT id FROM presidents WHERE number = 34), 'On this day in 1960, an American U-2 spy plane was shot down over the Soviet Union, and pilot Francis Gary Powers was captured. President Eisenhower''s initial denials were quickly exposed, wrecking the Paris Summit and damaging U.S.-Soviet relations.', 'scandal'),
(5, 7, 1915,  (SELECT id FROM presidents WHERE number = 28), 'On this day in 1915, a German U-boat sank the Lusitania, killing 1,198 people including 128 Americans. President Wilson''s stern protests began a two-year diplomatic crisis that ultimately drew the United States into World War I.', 'war'),
(5, 8, 1884, (SELECT id FROM presidents WHERE number = 33), 'On this day in 1884, Harry S. Truman was born in Lamar, Missouri. The farm boy who never attended college became president in the most consequential year in modern history, dropping the atomic bomb, founding NATO, and beginning the Cold War.', 'birth'),
(5, 8, 1945,  (SELECT id FROM presidents WHERE number = 33), 'On this day in 1945, President Harry Truman announced Victory in Europe — V-E Day — marking Germany''s unconditional surrender and the end of World War II in Europe. Truman received the news on his 61st birthday.', 'war'),
(5, 13, 1846, (SELECT id FROM presidents WHERE number = 11), 'On this day in 1846, President James K. Polk signed the declaration of war against Mexico. The resulting Mexican-American War added California, Nevada, Utah, Arizona, New Mexico, and parts of Colorado and Wyoming to the United States.', 'war'),
(5, 14, 1948, (SELECT id FROM presidents WHERE number = 33), 'On this day in 1948, just eleven minutes after Israel declared independence, President Truman granted it U.S. recognition — making America the first nation in the world to recognize the new Jewish state, over the fierce objections of his State Department.', 'achievement'),
(5, 17, 1954, (SELECT id FROM presidents WHERE number = 34), 'On this day in 1954, the Supreme Court issued its unanimous Brown v. Board of Education ruling, declaring school segregation unconstitutional. President Eisenhower was privately unenthusiastic but enforced the ruling — eventually sending 101st Airborne troops to Little Rock.', 'legislation'),
(5, 20, 1862, (SELECT id FROM presidents WHERE number = 16), 'On this day in 1862, President Abraham Lincoln signed the Homestead Act, offering 160 acres of free public land to any citizen willing to settle and farm it for five years. The law transformed the American West and brought millions of settlers to the frontier.', 'legislation'),
(5, 25, 1961, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1961, President Kennedy stood before Congress and issued the most audacious challenge in the history of exploration: to land a man on the Moon and return him safely to Earth before the decade was out. Eight years and four months later, it was done.', 'achievement'),
(5, 26, 1868, (SELECT id FROM presidents WHERE number = 17), 'On this day in 1868, the U.S. Senate acquitted President Andrew Johnson of impeachment charges by a single vote — the closest any sitting president has come to being removed from office by the Senate in the 19th century.', 'scandal'),
(5, 29, 1917, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1917, John F. Kennedy was born in Brookline, Massachusetts. The youngest elected president and the first Catholic president, he navigated the Cuban Missile Crisis, launched the space program, and inspired a generation before his assassination in 1963.', 'birth'),
(5, 4, 1970,  (SELECT id FROM presidents WHERE number = 37), 'On this day in 1970, Ohio National Guard soldiers killed four student protesters at Kent State University during demonstrations against President Nixon''s invasion of Cambodia — a moment of profound national trauma that deepened the country''s divisions over Vietnam.', 'scandal'),
(5, 22, 1856, (SELECT id FROM presidents WHERE number = 14), 'On this day in 1856, pro-slavery Congressman Preston Brooks beat anti-slavery Senator Charles Sumner unconscious on the Senate floor with a metal cane. The brutal assault shocked the North and inflamed sectional tensions during President Pierce''s troubled presidency.', 'scandal'),
(5, 31, 1790, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1790, President George Washington signed the nation''s first copyright law, establishing legal protection for authors and creators — an early signal that the new republic intended to nurture intellectual and cultural achievement alongside commerce.', 'legislation'),
(5, 19, 1921, (SELECT id FROM presidents WHERE number = 29), 'On this day in 1921, President Warren G. Harding signed the Emergency Quota Act, imposing the first numerical limits on immigration in American history — a profound shift that would define immigration policy for decades to come.', 'legislation'),

-- ─── JUNE ─────────────────────────────────────────────────────────────────────

(6, 1, 1868,  (SELECT id FROM presidents WHERE number = 15), 'On this day in 1868, James Buchanan died at age 77 at Wheatland, his Pennsylvania estate. The only bachelor president, he outlived the Civil War that he had failed to prevent — watching the Union he had failed to protect nearly destroy itself.', 'death'),
(6, 5, 2004,  (SELECT id FROM presidents WHERE number = 40), 'On this day in 2004, Ronald Reagan died at his Bel Air home after a decade-long battle with Alzheimer''s disease, at age 93. He was the longest-lived president in American history and received one of the largest state funerals in U.S. history.', 'death'),
(6, 6, 1944,  (SELECT id FROM presidents WHERE number = 32), 'On this day in 1944, Allied forces stormed the beaches of Normandy in the largest seaborne invasion in history. President Roosevelt addressed the nation in prayer: "Lead us to the saving of our country, and with our sister nations into a world unity that will spell a sure peace."', 'war'),
(6, 12, 1924, (SELECT id FROM presidents WHERE number = 41), 'On this day in 1924, George H.W. Bush was born in Milton, Massachusetts. A decorated World War II naval aviator, he served as CIA director, envoy to China, vice president, and 41st president — overseeing the fall of the Berlin Wall and the liberation of Kuwait.', 'birth'),
(6, 12, 1987, (SELECT id FROM presidents WHERE number = 40), 'On this day in 1987, President Ronald Reagan stood at the Brandenburg Gate in Berlin and delivered his famous challenge: "Mr. Gorbachev, tear down this wall!" Two and a half years later, the Berlin Wall fell and the Cold War began its end.', 'achievement'),
(6, 14, 1946, (SELECT id FROM presidents WHERE number = 45), 'On this day in 1946, Donald Trump was born in Queens, New York. He became the 45th president after a stunning electoral upset in 2016, and made history as the first former president to be convicted of a felony — 34 counts in 2024.', 'birth'),
(6, 15, 1849, (SELECT id FROM presidents WHERE number = 11), 'On this day in 1849, James K. Polk died of cholera at age 53, just 103 days after leaving office — making him the shortest-lived former president. Despite his brief life, he achieved every major goal he set at the start of his single term.', 'death'),
(6, 17, 1972, (SELECT id FROM presidents WHERE number = 37), 'On this day in 1972, five men were arrested for breaking into the Democratic National Committee headquarters at the Watergate complex in Washington, D.C. — setting in motion the scandal that would force President Nixon to become the only president to resign from office.', 'scandal'),
(6, 18, 1812, (SELECT id FROM presidents WHERE number = 4),  'On this day in 1812, President James Madison signed the declaration of war against Great Britain, beginning the War of 1812. The conflict went so badly that British troops burned the White House two years later — the only time since the Revolution that foreign forces occupied the U.S. capital.', 'war'),
(6, 22, 1944, (SELECT id FROM presidents WHERE number = 32), 'On this day in 1944, President Franklin D. Roosevelt signed the Servicemen''s Readjustment Act — the GI Bill — providing veterans with college tuition, home loans, and job training. It is credited with creating the American middle class and remains the most transformative piece of social legislation in U.S. history.', 'legislation'),
(6, 24, 1908, (SELECT id FROM presidents WHERE number = 22), 'On this day in 1908, Grover Cleveland died at his Princeton home at age 71. The only president to serve two non-consecutive terms, he was a man of stubborn integrity in an era of rampant political corruption — vetoing more bills than all previous presidents combined.', 'death'),
(6, 25, 1876, (SELECT id FROM presidents WHERE number = 18), 'On this day in 1876, Lt. Col. George Custer and 268 soldiers were killed at the Battle of Little Bighorn in Montana — the worst defeat of U.S. forces by Native Americans, occurring during President Grant''s administration, which was simultaneously negotiating broken treaty after broken treaty.', 'war'),
(6, 26, 1963, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1963, President Kennedy delivered his famous "Ich bin ein Berliner" speech at the Berlin Wall, pledging American solidarity with the people of West Berlin. It was one of the most electrifying moments of his presidency and of the Cold War era.', 'achievement'),
(6, 27, 1950, (SELECT id FROM presidents WHERE number = 33), 'On this day in 1950, President Harry Truman ordered U.S. forces into Korea after North Korea invaded the South — without a formal declaration of war, calling it a "police action." The conflict lasted three years and cost 36,000 American lives.', 'war'),
(6, 28, 1836, (SELECT id FROM presidents WHERE number = 4),  'On this day in 1836, James Madison died at age 85 at his Virginia plantation — the last surviving Founding Father and the architect of the Constitution. He reportedly refused medicine that might have prolonged his life just to die on July 4th, saying the date no longer mattered.', 'death'),
(6, 29, 1956, (SELECT id FROM presidents WHERE number = 34), 'On this day in 1956, President Dwight D. Eisenhower signed the Federal Aid Highway Act, creating the 41,000-mile Interstate Highway System — the largest public works project in American history, inspired by his experiences with the German Autobahn during World War II.', 'legislation'),

-- ─── JULY ─────────────────────────────────────────────────────────────────────

(7, 2, 1881,  (SELECT id FROM presidents WHERE number = 20), 'On this day in 1881, President James Garfield was shot at a Washington train station by Charles Guiteau, a disappointed office-seeker. Garfield survived the bullet but died 79 days later — largely due to doctors repeatedly probing his wound with unwashed fingers.', 'death'),
(7, 2, 1964,  (SELECT id FROM presidents WHERE number = 36), 'On this day in 1964, President Lyndon B. Johnson signed the Civil Rights Act of 1964 — the most sweeping civil rights legislation since Reconstruction — outlawing discrimination based on race, color, religion, sex, or national origin.', 'legislation'),
(7, 4, 1826,  (SELECT id FROM presidents WHERE number = 2),  'On this day in 1826, former President John Adams died at age 90 — on the 50th anniversary of the Declaration of Independence. His last words were "Thomas Jefferson survives." He did not know Jefferson had died hours earlier, also on the Fourth of July.', 'death'),
(7, 4, 1826,  (SELECT id FROM presidents WHERE number = 3),  'On this day in 1826, Thomas Jefferson died at Monticello at age 83 — on the 50th anniversary of the Declaration of Independence, the same day as his old friend and rival John Adams. His last words were reportedly "Is it the Fourth?"', 'death'),
(7, 4, 1831,  (SELECT id FROM presidents WHERE number = 5),  'On this day in 1831, James Monroe died in New York City at age 73 — making him the third of the first five presidents to die on July 4th. His death on Independence Day was seen as a final tribute to the republic he had helped build.', 'death'),
(7, 4, 1872,  (SELECT id FROM presidents WHERE number = 30), 'On this day in 1872, Calvin Coolidge was born in Plymouth Notch, Vermont — the only U.S. president born on the Fourth of July. The frugal and reticent "Silent Cal" presided over the booming 1920s economy before the Great Depression undid his successor.', 'birth'),
(7, 6, 1946,  (SELECT id FROM presidents WHERE number = 43), 'On this day in 1946, George W. Bush was born in New Haven, Connecticut. The 43rd president led the country after September 11, launched wars in Afghanistan and Iraq, and expanded government surveillance in ways that reshaped American life for a generation.', 'birth'),
(7, 9, 1850,  (SELECT id FROM presidents WHERE number = 12), 'On this day in 1850, President Zachary Taylor died suddenly of acute gastroenteritis at age 65, just 16 months into his term. The hero of the Mexican-American War had attended a July 4th ceremony at the Washington Monument in extreme heat, consumed large amounts of iced milk and cherries, and fell violently ill.', 'death'),
(7, 11, 1767, (SELECT id FROM presidents WHERE number = 6),  'On this day in 1767, John Quincy Adams was born in Braintree, Massachusetts — son of President John Adams. He became the 6th president, and after his term, served 17 years in the House as a fierce opponent of slavery, dying on the House floor in 1848.', 'birth'),
(7, 14, 1913, (SELECT id FROM presidents WHERE number = 38), 'On this day in 1913, Gerald Ford was born in Omaha, Nebraska. The only president never elected to either the presidency or vice presidency, he famously said upon taking office after Nixon resigned: "Our long national nightmare is over."', 'birth'),
(7, 20, 1969, (SELECT id FROM presidents WHERE number = 37), 'On this day in 1969, Neil Armstrong became the first human to walk on the Moon, fulfilling President Kennedy''s challenge from eight years earlier. President Nixon called astronauts Armstrong and Aldrin from the Oval Office in "the most historic phone call ever made."', 'achievement'),
(7, 23, 1885, (SELECT id FROM presidents WHERE number = 18), 'On this day in 1885, Ulysses S. Grant died of throat cancer at age 63, having finished writing his celebrated Personal Memoirs just days earlier — a literary masterpiece that secured financial security for his family and is still read by military historians today.', 'death'),
(7, 26, 1945, (SELECT id FROM presidents WHERE number = 33), 'On this day in 1945, President Truman issued the Potsdam Declaration demanding Japan''s unconditional surrender, warning of "prompt and utter destruction" if refused. Japan''s silence sealed the decision to use the atomic bomb.', 'war'),
(7, 26, 1990, (SELECT id FROM presidents WHERE number = 41), 'On this day in 1990, President George H.W. Bush signed the Americans with Disabilities Act — the world''s most comprehensive civil rights law protecting people with disabilities, granting equal access and opportunity to more than 43 million Americans.', 'legislation'),
(7, 30, 1965, (SELECT id FROM presidents WHERE number = 36), 'On this day in 1965, President Lyndon B. Johnson signed Medicare and Medicaid into law in Independence, Missouri — with former President Truman, whose own national health insurance proposal had been rejected 20 years earlier, seated at his side.', 'legislation'),
(7, 31, 1875, (SELECT id FROM presidents WHERE number = 17), 'On this day in 1875, Andrew Johnson died of a stroke at age 66 at his daughter''s home in Tennessee. The first impeached president had recently been elected back to the U.S. Senate — the only former president to return to that chamber.', 'death'),

-- ─── AUGUST ───────────────────────────────────────────────────────────────────

(8, 2, 1923,  (SELECT id FROM presidents WHERE number = 29), 'On this day in 1923, President Warren G. Harding died suddenly in San Francisco at age 57, while on a Western speaking tour. His death came just as the Teapot Dome scandal was unraveling, and his legacy was consumed by the corruption of his administration.', 'death'),
(8, 4, 1961,  (SELECT id FROM presidents WHERE number = 44), 'On this day in 1961, Barack Obama was born in Honolulu, Hawaii. The 44th president and first African American to hold the office was awarded the Nobel Peace Prize in his first year — and his election was widely described as a transformative moment in American history.', 'birth'),
(8, 5, 1861,  (SELECT id FROM presidents WHERE number = 16), 'On this day in 1861, President Lincoln signed the Revenue Act of 1861, imposing the first federal income tax in American history — a 3% tax on incomes over $800 — to fund the Civil War. The tax was repealed after the war and not restored until 1913.', 'legislation'),
(8, 6, 1945,  (SELECT id FROM presidents WHERE number = 33), 'On this day in 1945, President Harry Truman authorized the dropping of the atomic bomb on Hiroshima, Japan. The explosion killed an estimated 80,000 people instantly and reshaped international relations — a decision historians debate to this day.', 'war'),
(8, 6, 1965,  (SELECT id FROM presidents WHERE number = 36), 'On this day in 1965, President Lyndon B. Johnson signed the Voting Rights Act — one of the most consequential pieces of legislation in American history — outlawing the discriminatory practices that had blocked millions of Black voters from the polls for a century.', 'legislation'),
(8, 7, 1964,  (SELECT id FROM presidents WHERE number = 36), 'On this day in 1964, Congress passed the Gulf of Tonkin Resolution, giving President Johnson sweeping authority to escalate U.S. involvement in Vietnam. The resolution was based on a disputed attack, and the war it authorized would cost 58,000 American lives.', 'war'),
(8, 9, 1945,  (SELECT id FROM presidents WHERE number = 33), 'On this day in 1945, the United States dropped a second atomic bomb — on Nagasaki, Japan. President Truman defended the decision as necessary to end the war without a land invasion that military planners estimated could cost a million American casualties.', 'war'),
(8, 9, 1974,  (SELECT id FROM presidents WHERE number = 37), 'On this day in 1974, Richard Nixon became the only U.S. president to resign from office, stepping down in the face of certain impeachment for his role in the Watergate cover-up. He told the nation it was time to "start the process of healing."', 'scandal'),
(8, 10, 1874, (SELECT id FROM presidents WHERE number = 31), 'On this day in 1874, Herbert Hoover was born in West Branch, Iowa — the first president born west of the Mississippi River. A self-made millionaire and brilliant administrator, his presidency was defined by the Great Depression that struck just months after he took office.', 'birth'),
(8, 14, 1935, (SELECT id FROM presidents WHERE number = 32), 'On this day in 1935, President Franklin D. Roosevelt signed the Social Security Act — the cornerstone of the modern American welfare state — providing retirement benefits, unemployment insurance, and aid to the elderly poor and disabled.', 'legislation'),
(8, 15, 1914, (SELECT id FROM presidents WHERE number = 28), 'On this day in 1914, the Panama Canal officially opened to commercial traffic, completing one of the greatest engineering achievements in human history. Though Theodore Roosevelt conceived it, President Wilson''s administration saw it through to completion.', 'achievement'),
(8, 19, 1946, (SELECT id FROM presidents WHERE number = 42), 'On this day in 1946, Bill Clinton was born in Hope, Arkansas. The 42nd president presided over the longest peacetime economic expansion in U.S. history and balanced the federal budget — before his presidency was consumed by impeachment over the Monica Lewinsky scandal.', 'birth'),
(8, 20, 1833, (SELECT id FROM presidents WHERE number = 23), 'On this day in 1833, Benjamin Harrison was born in North Bend, Ohio — the grandson of President William Henry Harrison. His single term saw six states admitted to the Union and the passage of the Sherman Antitrust Act, the first federal law curbing corporate monopolies.', 'birth'),
(8, 24, 1814, (SELECT id FROM presidents WHERE number = 4),  'On this day in 1814, British forces captured and burned Washington, D.C. — including the White House and the Capitol — while President Madison fled the city. First Lady Dolley Madison famously saved Gilbert Stuart''s portrait of George Washington before escaping.', 'war'),
(8, 27, 1908, (SELECT id FROM presidents WHERE number = 36), 'On this day in 1908, Lyndon B. Johnson was born near Stonewall, Texas. He launched the Great Society, passed landmark civil rights legislation, created Medicare and Medicaid — but his escalation of the Vietnam War drove him from the presidency and defined his legacy.', 'birth'),
(8, 28, 1963, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1963, Martin Luther King Jr. delivered his "I Have a Dream" speech to 250,000 people at the March on Washington — a galvanizing moment that helped President Kennedy advance his landmark civil rights bill through a reluctant Congress.', 'achievement'),

-- ─── SEPTEMBER ────────────────────────────────────────────────────────────────

(9, 2, 1945,  (SELECT id FROM presidents WHERE number = 33), 'On this day in 1945, Japan formally surrendered aboard the USS Missouri in Tokyo Bay, ending World War II. President Truman proclaimed V-J Day, bringing the most destructive conflict in human history to its close — six years and 70 million lives after it began.', 'war'),
(9, 6, 1901,  (SELECT id FROM presidents WHERE number = 25), 'On this day in 1901, President William McKinley was shot by anarchist Leon Czolgosz at the Pan-American Exposition in Buffalo, New York. He lingered for eight days, dying on September 14 — the third U.S. president to be assassinated.', 'death'),
(9, 7, 1977,  (SELECT id FROM presidents WHERE number = 39), 'On this day in 1977, President Jimmy Carter and Panamanian leader Omar Torrijos signed the Panama Canal Treaties, agreeing to transfer full control of the canal to Panama by December 31, 1999 — a politically costly act of statesmanship that Carter considered his finest moment.', 'legislation'),
(9, 8, 1974,  (SELECT id FROM presidents WHERE number = 38), 'On this day in 1974, President Gerald Ford issued a full and unconditional pardon to former President Richard Nixon for any crimes he may have committed while in office. The decision was enormously unpopular and likely cost Ford the 1976 presidential election.', 'scandal'),
(9, 11, 2001, (SELECT id FROM presidents WHERE number = 43), 'On this day in 2001, al-Qaeda terrorists hijacked four aircraft and attacked the World Trade Center and the Pentagon, killing nearly 3,000 people in the deadliest foreign attack on American soil in history. President Bush addressed a shaken nation that evening.', 'war'),
(9, 12, 1962, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1962, President Kennedy delivered his famous "We choose to go to the Moon" speech at Rice University in Houston, explaining America''s space ambitions with a mixture of poetry, humor, and absolute conviction that electrified the nation.', 'achievement'),
(9, 14, 1901, (SELECT id FROM presidents WHERE number = 26), 'On this day in 1901, Theodore Roosevelt was sworn in as the 26th president at age 42 — the youngest person ever to assume the presidency — following the death of President McKinley. He promised to continue McKinley''s policies, then proceeded to transform the presidency.', 'inauguration'),
(9, 17, 1978, (SELECT id FROM presidents WHERE number = 39), 'On this day in 1978, President Jimmy Carter announced the Camp David Accords — a peace framework between Egypt and Israel brokered after 13 days of secret and exhausting negotiations — the greatest diplomatic achievement of his presidency.', 'achievement'),
(9, 19, 1881, (SELECT id FROM presidents WHERE number = 20), 'On this day in 1881, President James A. Garfield died of his gunshot wounds, 79 days after being shot. His death outraged the nation and led directly to the Pendleton Civil Service Reform Act of 1883, ending the corrupt "spoils system" of government hiring.', 'death'),
(9, 22, 1862, (SELECT id FROM presidents WHERE number = 16), 'On this day in 1862, President Lincoln issued the Preliminary Emancipation Proclamation, announcing his intention to free enslaved people in Confederate states — a masterstroke that transformed the Civil War from a fight to preserve the Union into a moral crusade against slavery.', 'achievement'),
(9, 23, 1952, (SELECT id FROM presidents WHERE number = 34), 'On this day in 1952, vice-presidential candidate Richard Nixon delivered his famous "Checkers Speech" on national television, defending himself against accusations of campaign fund misuse. The emotional address saved his place on Eisenhower''s ticket.', 'scandal'),
(9, 24, 1789, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1789, President George Washington signed the Judiciary Act, establishing the Supreme Court of the United States and creating the federal court system — the foundation of the judicial branch that has shaped American law ever since.', 'legislation'),
(9, 25, 1957, (SELECT id FROM presidents WHERE number = 34), 'On this day in 1957, President Eisenhower ordered 1,000 Army paratroopers from the 101st Airborne Division to Little Rock, Arkansas, to enforce the court-ordered desegregation of Central High School against the defiance of Governor Orval Faubus.', 'achievement'),
(9, 26, 1960, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1960, Senator Kennedy and Vice President Nixon faced off in the first televised presidential debate. Those who heard it on radio thought Nixon won. Those who watched on TV thought Kennedy won — demonstrating forever the transformative power of television in politics.', 'achievement'),
(9, 30, 1962, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1962, James Meredith became the first African American student at the University of Mississippi after President Kennedy ordered federal marshals and National Guard troops to enforce court-ordered desegregation against violent riots on campus.', 'achievement'),
(9, 3, 1783,  (SELECT id FROM presidents WHERE number = 1),  'On this day in 1783, the Treaty of Paris was signed, formally ending the Revolutionary War. Future president George Washington had commanded the Continental Army to the victory that made this peace possible — against what had been the world''s most powerful military.', 'achievement'),

-- ─── OCTOBER ──────────────────────────────────────────────────────────────────

(10, 1, 1924, (SELECT id FROM presidents WHERE number = 39), 'On this day in 1924, Jimmy Carter was born in Plains, Georgia — the first U.S. president to be born in a hospital. After a single troubled term in the White House, he became arguably the most admired and productive former president in American history.', 'birth'),
(10, 2, 1919, (SELECT id FROM presidents WHERE number = 28), 'On this day in 1919, President Woodrow Wilson suffered a severe stroke while barnstorming the country to build support for the League of Nations — leaving him incapacitated for the rest of his term while First Lady Edith Wilson quietly managed presidential affairs.', 'achievement'),
(10, 4, 1822, (SELECT id FROM presidents WHERE number = 19), 'On this day in 1822, Rutherford B. Hayes was born in Delaware, Ohio. His disputed 1876 election victory was resolved by a special congressional commission — a political deal that ended Reconstruction and left Black Americans in the South without federal protection.', 'birth'),
(10, 5, 1829, (SELECT id FROM presidents WHERE number = 21), 'On this day in 1829, Chester A. Arthur was born in Fairfield, Vermont. Assuming the presidency after Garfield''s assassination, the machine politician surprised everyone by championing civil service reform, forever changing how the federal government hired its employees.', 'birth'),
(10, 7, 2001, (SELECT id FROM presidents WHERE number = 43), 'On this day in 2001, the United States launched Operation Enduring Freedom, beginning the invasion of Afghanistan in response to the September 11 attacks. President Bush vowed to dismantle al-Qaeda and topple the Taliban government that had sheltered them.', 'war'),
(10, 14, 1890, (SELECT id FROM presidents WHERE number = 34), 'On this day in 1890, Dwight D. Eisenhower was born in Denison, Texas. The Supreme Allied Commander who oversaw D-Day and the liberation of Europe became the 34th president — warning the nation on his way out of the growing power of the "military-industrial complex."', 'birth'),
(10, 16, 1901, (SELECT id FROM presidents WHERE number = 26), 'On this day in 1901, President Theodore Roosevelt invited Booker T. Washington to dine at the White House — the first time an African American had dined with a president — causing a storm of racist outrage across the South that shocked and angered Roosevelt.', 'achievement'),
(10, 19, 1781, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1781, British General Cornwallis surrendered at Yorktown, Virginia, effectively ending the Revolutionary War. General George Washington, the future president, accepted the victory that secured American independence after six years of brutal conflict.', 'war'),
(10, 20, 1964, (SELECT id FROM presidents WHERE number = 31), 'On this day in 1964, Herbert Hoover died in New York City at age 90 — the longest-lived president in American history at the time. He had spent his final decades working to rehabilitate his reputation, and lived long enough to see it partially succeed.', 'death'),
(10, 22, 1962, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1962, President Kennedy addressed the nation to reveal the Cuban Missile Crisis, announcing a naval blockade of Cuba and demanding the Soviet Union remove its nuclear missiles — bringing the world to the closest it has ever come to nuclear war.', 'war'),
(10, 22, 1986, (SELECT id FROM presidents WHERE number = 40), 'On this day in 1986, President Ronald Reagan signed the Tax Reform Act — the most sweeping overhaul of the U.S. tax code in history — simplifying the tax brackets and cutting the top marginal rate from 50% to 28% in a bipartisan achievement.', 'legislation'),
(10, 27, 1858, (SELECT id FROM presidents WHERE number = 26), 'On this day in 1858, Theodore Roosevelt was born in New York City. The youngest president in history at 42, he busted trusts, conserved 230 million acres of public land, built the Panama Canal, won the Nobel Peace Prize, and redefined the modern presidency.', 'birth'),
(10, 28, 1962, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1962, Soviet Premier Khrushchev agreed to remove Soviet missiles from Cuba, ending the Cuban Missile Crisis. President Kennedy''s combination of firmness and back-channel diplomacy had stepped the world back from the nuclear brink.', 'achievement'),
(10, 29, 1929, (SELECT id FROM presidents WHERE number = 31), 'On this day in 1929, the U.S. stock market collapsed on "Black Tuesday," destroying billions in wealth and beginning the Great Depression. President Hoover''s failure to respond with sufficient force would define — and doom — his presidency.', 'achievement'),
(10, 30, 1735, (SELECT id FROM presidents WHERE number = 2),  'On this day in 1735, John Adams was born in Braintree, Massachusetts. The nation''s first vice president and second president, he navigated the young republic through its first foreign crises and ensured the first peaceful transfer of presidential power in modern democratic history.', 'birth'),

-- ─── NOVEMBER ─────────────────────────────────────────────────────────────────

(11, 2, 1795, (SELECT id FROM presidents WHERE number = 11), 'On this day in 1795, James K. Polk was born in Mecklenburg County, North Carolina. The "dark horse" president is the only commander-in-chief to achieve every single goal he announced at the start of his presidency — including adding more territory to America than any president except Jefferson.', 'birth'),
(11, 2, 1865, (SELECT id FROM presidents WHERE number = 29), 'On this day in 1865, Warren G. Harding was born in Blooming Grove, Ohio. The handsome and affable 29th president coined "normalcy" and presided over the Roaring Twenties prosperity — but his administration was plagued by the Teapot Dome scandal and cronyism.', 'birth'),
(11, 3, 1986, (SELECT id FROM presidents WHERE number = 40), 'On this day in 1986, a Lebanese newspaper exposed the secret sale of U.S. weapons to Iran in exchange for hostages — the beginning of the Iran-Contra scandal, which revealed that Reagan administration officials had illegally diverted profits to fund Nicaraguan rebels.', 'scandal'),
(11, 4, 2008, (SELECT id FROM presidents WHERE number = 44), 'On this day in 2008, Barack Obama won the presidential election, becoming the first African American elected president of the United States. His victory was greeted with celebrations around the world and described as a historic turning point in American race relations.', 'achievement'),
(11, 6, 1860, (SELECT id FROM presidents WHERE number = 16), 'On this day in 1860, Abraham Lincoln won the presidency with less than 40% of the popular vote, carrying no Southern states. South Carolina seceded within months, and six more states followed — plunging the nation into civil war.', 'achievement'),
(11, 9, 1989, (SELECT id FROM presidents WHERE number = 41), 'On this day in 1989, the Berlin Wall fell as East Germany opened its borders — the defining moment of the end of the Cold War. President George H.W. Bush responded with careful restraint, determined not to humiliate the Soviet Union as it released its grip on Eastern Europe.', 'achievement'),
(11, 18, 1886, (SELECT id FROM presidents WHERE number = 21), 'On this day in 1886, Chester A. Arthur died of Bright''s disease at age 56. He had kept his terminal kidney disease secret throughout his presidency, and his decision not to seek re-election was shaped by his failing health — though he never told the public why.', 'death'),
(11, 19, 1831, (SELECT id FROM presidents WHERE number = 20), 'On this day in 1831, James A. Garfield was born in Orange, Ohio — the last president born in a log cabin. An accidental president shot four months into his term, his death galvanized reform of the patronage system that had been the source of his assassin''s grievance.', 'birth'),
(11, 19, 1863, (SELECT id FROM presidents WHERE number = 16), 'On this day in 1863, President Abraham Lincoln delivered the Gettysburg Address at the dedication of the Soldiers'' National Cemetery — a 272-word speech that took just two minutes to deliver and redefined the purpose of the Civil War for all of American history.', 'achievement'),
(11, 20, 1942, (SELECT id FROM presidents WHERE number = 46), 'On this day in 1942, Joe Biden was born in Scranton, Pennsylvania. The 46th president previously served as the longest-serving senator from Delaware and as vice president under Barack Obama — making him the oldest person ever elected to the presidency at age 77.', 'birth'),
(11, 22, 1963, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1963, President John F. Kennedy was assassinated in Dallas, Texas, shot while riding in a motorcade through Dealey Plaza. He was 46 years old. Lyndon Johnson was sworn in as president aboard Air Force One, with a blood-spattered Jacqueline Kennedy at his side.', 'death'),
(11, 23, 1804, (SELECT id FROM presidents WHERE number = 14), 'On this day in 1804, Franklin Pierce was born in Hillsborough, New Hampshire. The 14th president is often ranked among the worst for supporting the Kansas-Nebraska Act, which reopened the slavery debate and accelerated the nation''s march toward civil war.', 'birth'),
(11, 24, 1784, (SELECT id FROM presidents WHERE number = 12), 'On this day in 1784, Zachary Taylor was born in Orange County, Virginia. A celebrated Mexican-American War general who had never voted in a presidential election, he died after just 16 months in office — before ever truly setting foot in the political world he had entered.', 'birth'),
(11, 25, 1963, (SELECT id FROM presidents WHERE number = 35), 'On this day in 1963, President Kennedy was buried at Arlington National Cemetery as the world watched in shared grief. His three-year-old son John Jr. saluted the passing coffin in what became one of the most iconic and heartbreaking images in American history.', 'achievement'),
(11, 30, 2018, (SELECT id FROM presidents WHERE number = 41), 'On this day in 2018, George H.W. Bush died at age 94 in Houston, Texas — the longest-lived president in American history at that time. His son, former President George W. Bush, delivered a tearful eulogy at the state funeral, calling him "the best father a son or daughter could have."', 'death'),

-- ─── DECEMBER ─────────────────────────────────────────────────────────────────

(12, 5, 1782, (SELECT id FROM presidents WHERE number = 8),  'On this day in 1782, Martin Van Buren was born in Kinderhook, New York — the first president born as an American citizen rather than a British subject. His presidency was consumed by the Panic of 1837, and he is remembered as a gifted political organizer who failed as a crisis leader.', 'birth'),
(12, 7, 1787, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1787, Delaware became the first state to ratify the U.S. Constitution — beginning the process that created the framework of government under which George Washington would serve as the nation''s first president two years later.', 'achievement'),
(12, 7, 1941, (SELECT id FROM presidents WHERE number = 32), 'On this day in 1941, Japanese forces launched a surprise attack on the U.S. naval base at Pearl Harbor, Hawaii, killing 2,403 Americans and wounding 1,178 more. President Roosevelt called it "a date which will live in infamy."', 'war'),
(12, 8, 1941, (SELECT id FROM presidents WHERE number = 32), 'On this day in 1941, President Franklin D. Roosevelt delivered his "Day of Infamy" speech to a joint session of Congress, requesting a declaration of war against Japan. Congress declared war within 33 minutes — with a single dissenting vote.', 'war'),
(12, 10, 1906, (SELECT id FROM presidents WHERE number = 26), 'On this day in 1906, Theodore Roosevelt became the first American president to be awarded the Nobel Peace Prize, honored for his role in mediating an end to the Russo-Japanese War of 1905 — a remarkable act of diplomacy by a president better known for bellicosity.', 'achievement'),
(12, 14, 1799, (SELECT id FROM presidents WHERE number = 1),  'On this day in 1799, George Washington died at Mount Vernon at age 67, two days after developing a severe throat infection. The father of his country had set the precedent — voluntarily giving up power after two terms — that defined American democracy for a century and a half.', 'death'),
(12, 18, 2019, (SELECT id FROM presidents WHERE number = 45), 'On this day in 2019, the U.S. House of Representatives voted to impeach President Donald Trump on charges of abuse of power and obstruction of Congress related to pressuring Ukraine to investigate a political rival — the third presidential impeachment in American history.', 'scandal'),
(12, 19, 1998, (SELECT id FROM presidents WHERE number = 42), 'On this day in 1998, the U.S. House of Representatives voted to impeach President Bill Clinton on charges of perjury and obstruction of justice related to the Monica Lewinsky scandal — the second presidential impeachment, and the first of a president elected in the modern era.', 'scandal'),
(12, 23, 1913, (SELECT id FROM presidents WHERE number = 28), 'On this day in 1913, President Woodrow Wilson signed the Federal Reserve Act into law, creating the Federal Reserve System that regulates American monetary policy, banking, and interest rates — one of the most consequential pieces of legislation in American economic history.', 'legislation'),
(12, 24, 1814, (SELECT id FROM presidents WHERE number = 4),  'On this day in 1814, American and British diplomats signed the Treaty of Ghent, ending the War of 1812 — though neither side knew it, Andrew Jackson would fight and win the Battle of New Orleans three weeks later, becoming the war''s greatest hero after the war was already over.', 'war'),
(12, 26, 1972, (SELECT id FROM presidents WHERE number = 33), 'On this day in 1972, Harry S. Truman died at age 88 in Kansas City, Missouri. The plain-speaking Missourian who had ended World War II, founded NATO, and begun the Cold War left office deeply unpopular — only to be recognized by historians as one of the great presidents.', 'death'),
(12, 26, 2006, (SELECT id FROM presidents WHERE number = 38), 'On this day in 2006, Gerald Ford died at age 93 in Rancho Mirage, California — the longest-lived president in American history at that time. The only president to hold the office without being elected to either the presidency or vice presidency, he healed a wounded nation after Watergate.', 'death'),
(12, 28, 1856, (SELECT id FROM presidents WHERE number = 28), 'On this day in 1856, Woodrow Wilson was born in Staunton, Virginia. The idealistic 28th president created the Federal Reserve, the income tax, the League of Nations, and a new vision of American global leadership — and suffered a devastating stroke fighting to make it real.', 'birth'),
(12, 29, 1808, (SELECT id FROM presidents WHERE number = 17), 'On this day in 1808, Andrew Johnson was born in Raleigh, North Carolina. Lincoln''s vice president and successor, he was impeached for defying Congress during Reconstruction — his lenient policies toward the defeated South set back the rights of Black Americans for generations.', 'birth'),
(12, 29, 1845, (SELECT id FROM presidents WHERE number = 11), 'On this day in 1845, President James K. Polk signed the legislation admitting Texas as the 28th state of the United States — a milestone that immediately inflamed tensions with Mexico and set the stage for the Mexican-American War that would nearly double the size of the country.', 'legislation');
